import androidx.core.content.ContextCompat
import androidx.hilt.navigation.compose.hiltViewModel
import com.example.mileagetracker.R
import com.example.mileagetracker.data.model.TrackPoint
import com.example.mileagetracker.viewmodel.TrackDetailViewModel
import org.osmdroid.tileprovider.tilesource.TileSourceFactory
import org.osmdroid.util.GeoPoint
import org.osmdroid.views.MapView
import org.osmdroid.views.overlay.Marker
import org.osmdroid.views.overlay.Polyline
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun TrackDetailScreen(
 routeId: String,
 onNavigateBack: () -> Unit,
 viewModel: TrackDetailViewModel = hiltViewModel()
) {
 val savedTrack by viewModel.savedTrack.collectAsState()
 val trackPoints by viewModel.trackPoints.collectAsState()
 val isLoading by viewModel.isLoading.collectAsState()

 var mapView by remember { mutableStateOf<MapView?>(null) }

 // Load track data when screen is opened
 LaunchedEffect(routeId) {
 viewModel.loadTrackData(routeId)
 }

 Scaffold(
 topBar = {
 CenterAlignedTopAppBar(
 title = {
 Text(savedTrack?.name ?: "Track Details")
 },
 navigationIcon = {
 IconButton(onClick = onNavigateBack) {
 Icon(
 imageVector = Icons.Default.ArrowBack,
 contentDescription = "Go Back"
 )
 }
 }
 )
 }
 ) { paddingValues ->

 if (isLoading) {
 Box(
 modifier = Modifier
 .fillMaxSize()
 .padding(paddingValues),
 contentAlignment = Alignment.Center
 ) {
 CircularProgressIndicator()
 }
 } else if (savedTrack != null && trackPoints.isNotEmpty()) {
 Column(
 modifier = Modifier
 .fillMaxSize()
 .padding(paddingValues)
 ) {
 // Track Statistics Card
 TrackStatsCard(
 track = savedTrack!!,
 modifier = Modifier.padding(16.dp)
 )

 // Map Container
 Box(
 modifier = Modifier
 .fillMaxSize()
 .weight(1f)
 ) {
 AndroidView(
 factory = { context ->
 MapView(context).apply {
 setTileSource(TileSourceFactory.MAPNIK)
 setMultiTouchControls(true)
 mapView = this
 zoomController.setVisibility(
 org.osmdroid.views.CustomZoomButtonsController.Visibility.NEVER
 )

 // Set up the route
 setupRoute(this, trackPoints)
 }
 },
 update = { view ->
 // Update route if track points change
 setupRoute(view, trackPoints)
 },
 modifier = Modifier.fillMaxSize()
 )

 // Center Map FAB
 FloatingActionButton(
 onClick = {
 if (trackPoints.isNotEmpty()) {
 val centerPoint = GeoPoint(
 trackPoints.first().latitude,
 trackPoints.first().longitude
 )
 mapView?.controller?.animateTo(centerPoint)
 }
 },
 modifier = Modifier
 .align(Alignment.BottomEnd)
 .padding(16.dp),
 containerColor = MaterialTheme.colorScheme.primary
 ) {
 Icon(
 imageVector = Icons.Default.MyLocation,
 contentDescription = "Center Map"
 )
 }
 }
 }
 } else {
 Box(
 modifier = Modifier
 .fillMaxSize()
 .padding(paddingValues),
 contentAlignment = Alignment.Center
 ) {
 Column(horizontalAlignment = Alignment.CenterHorizontally) {
 Icon(
 imageVector = Icons.Default.Route,
 contentDescription = null,
 modifier = Modifier.size(64.dp),
 tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f)
 )
 Spacer(modifier = Modifier.height(16.dp))
 Text(
 text = "Track not found",
 style = MaterialTheme.typography.titleMedium,
 color = MaterialTheme.colorScheme.onSurfaceVariant
 )
 }
 }
 }
 }
}

@Composable
fun TrackStatsCard(
 track: com.example.mileagetracker.data.model.SavedTrack,
 modifier: Modifier = Modifier
) {
 Card(
 modifier = modifier.fillMaxWidth(),
 colors = CardDefaults.cardColors(
 containerColor = MaterialTheme.colorScheme.surface
 ),
 elevation = CardDefaults.cardElevation(defaultElevation = 4.dp)
 ) {
 Column(
 modifier = Modifier.padding(16.dp)
 ) {
 // Track name and date
 Text(
 text = track.name,
 style = MaterialTheme.typography.headlineSmall,
 fontWeight = FontWeight.Bold,
 color = MaterialTheme.colorScheme.onSurface
 )

 Spacer(modifier = Modifier.height(4.dp))

 Text(
 text = formatDate(track.createdAt),
 style = MaterialTheme.typography.bodyMedium,
 color = MaterialTheme.colorScheme.onSurfaceVariant
 )

 Spacer(modifier = Modifier.height(16.dp))

 // Stats Row
 Row(
 modifier = Modifier.fillMaxWidth(),
 horizontalArrangement = Arrangement.spacedBy(16.dp)
 ) {
 // Distance Stat
 StatItem(
 modifier = Modifier.weight(1f),
 icon = Icons.Default.Route,
 title = "Distance",
 value = String.format("%.2f km", track.distance / 1000),
 color = Color(0xFF2196F3)
 )

 // Duration Stat
 StatItem(
 modifier = Modifier.weight(1f),
 icon = Icons.Default.Timer,
 title = "Duration",
 value = formatDuration(track.duration),
 color = Color(0xFF9C27B0)
 )
 }
 }
 }
}

@Composable
fun StatItem(
 modifier: Modifier = Modifier,
 icon: androidx.compose.ui.graphics.vector.ImageVector,
 title: String,
 value: String,
 color: Color
) {
 Box(
 modifier = modifier
 .clip(RoundedCornerShape(12.dp))
 .background(color.copy(alpha = 0.1f))
 .padding(12.dp)
 ) {
 Column(
 horizontalAlignment = Alignment.CenterHorizontally
 ) {
 Icon(
 imageVector = icon,
 contentDescription = null,
 tint = color,
 modifier = Modifier.size(24.dp)
 )
 Spacer(modifier = Modifier.height(8.dp))
 Text(
 text = title,
 style = MaterialTheme.typography.bodySmall,
 color = MaterialTheme.colorScheme.onSurfaceVariant
 )
