 TextButton(
 onClick = {
 if (trackName.isNotBlank()) {
 scope.launch {
 viewModel.saveTrackWithName(
 name = trackName,
 distance = totalDistance.toDouble(),
 duration = duration,

 )
 showSaveDialog = false
 onSave()
 }
 }
 },
 enabled = trackName.isNotBlank()
 ) {
 Text("Save")
 }
 }
,
 dismissButton = {
 TextButton(
 onClick = { showSaveDialog = false }
 ) {
 Text("Cancel")
 }
 }
 )
 }

 Column(
 modifier = Modifier
 .fillMaxWidth()
 .padding(24.dp)
 ) {
 // Header
 Row(
 modifier = Modifier.fillMaxWidth(),
 horizontalArrangement = Arrangement.Center,
 verticalAlignment = Alignment.CenterVertically
 ) {
 Icon(
 imageVector = Icons.Default.CheckCircle,
 contentDescription = null,
 tint = Color(0xFF4CAF50),
 modifier = Modifier.size(32.dp)
 )
 Spacer(modifier = Modifier.width(12.dp))
 Text(
 text = "Journey Complete!",
 style = MaterialTheme.typography.headlineSmall,
 fontWeight = FontWeight.Bold,
 color = MaterialTheme.colorScheme.primary
 )
 }

 Spacer(modifier = Modifier.height(24.dp))

 // Stats Cards
 Row(
 modifier = Modifier.fillMaxWidth(),
 horizontalArrangement = Arrangement.spacedBy(12.dp)
 ) {
 // Distance Card
 StatCard(
 modifier = Modifier.weight(1f),
 icon = Icons.Default.Route,
 title = "Distance",
 value = String.format("%.2f km", totalDistance / 1000),
 color = Color(0xFF2196F3)
 )

 // Duration Card
 StatCard(
 modifier = Modifier.weight(1f),
 icon = Icons.Default.Timer,
 title = "Duration",
 value = formatDuration(duration),
 color = Color(0xFF9C27B0)
 )
 }

 Spacer(modifier = Modifier.height(16.dp))
 Spacer(modifier = Modifier.height(32.dp))

 // Action Buttons
 Row(
 modifier = Modifier.fillMaxWidth(),
 horizontalArrangement = Arrangement.spacedBy(12.dp)
 ) {
 // Cancel Button
 OutlinedButton(
 onClick = onCancel,
 modifier = Modifier
 .weight(1f)
 .height(56.dp),
 colors = ButtonDefaults.outlinedButtonColors(
 contentColor = Color.Red
 )
 ) {
 Icon(
 imageVector = Icons.Default.Close,
 contentDescription = null,
 modifier = Modifier.size(18.dp)
 )
 Spacer(modifier = Modifier.width(8.dp))
 Text("Discard", fontWeight = FontWeight.Medium)
 }

 // Save Button - Updated to show dialog
 Button(
 onClick = { showSaveDialog = true }, // Changed this line
 modifier = Modifier
 .weight(1f)
 .height(56.dp),
 colors = ButtonDefaults.buttonColors(
 containerColor = Color(0xFF4CAF50)
 )
 ) {
 Icon(
 imageVector = Icons.Default.Save,
 contentDescription = null,
 modifier = Modifier.size(18.dp)
 )
 Spacer(modifier = Modifier.width(8.dp))
 Text("Save Trip", fontWeight = FontWeight.Medium)
 }
 }

 Spacer(modifier = Modifier.height(16.dp))
 }
}

